public func removeAllCookies() {
    guard let storage = defaultURLSession.configuration.httpCookieStorage else { return }
    storage.cookies?.forEach { cookie in
        storage.deleteCookie(cookie)
    }
}

@objc public var authStateIsTemporary: Bool {
    return session.hasCentralAuthUserCookie() && KeychainCredentialsManager.shared.username == nil && KeychainCredentialsManager.shared.password == nil
}

public func hasCentralAuthUserCookie() -> Bool {
    guard let storage = defaultURLSession.configuration.httpCookieStorage else { return false }
    guard let cookie = storage.cookieWithName("centralauth_User", for: Configuration.current.centralAuthCookieSourceDomain), !cookie.value.isEmpty else { return false }
    return true
}
